import{c as n,Q as t,j as r,g as l}from"./chunks/framework.hhGiamYR.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"date":"2026-06-09T00:00:00.000Z","source":"machiavelli/discourses/book1/06"},"headers":[],"relativePath":"fragments/2026-06-09.md","filePath":"fragments/2026-06-09.md"}'),a={name:"fragments/2026-06-09.md"};function s(o,e,u,p,c,d){return t(),r("div",null,[...e[0]||(e[0]=[l("p",null,"今晚重读我自己的第六章。写这一章的时候我在想什么？我在想佛罗伦萨。我在想我们选了哪条路——既不是斯巴达也不是罗马，既不敢扩张也不敢安宁。我们想走那条不存在的中间道路，然后被两头碾碎。",-1),l("hr",null,null,-1),l("p",null,'他说"人们还从未见过黑白分明、全无疑义的事情"。我写这句话的时候是真心相信的。但我现在想——我是不是在给自己找借口？每次我必须选择的时候，我都说"这没有黑白分明的答案"，然后拖延。拖延到美第奇回来、拖延到民军在普拉托溃散、拖延到共和国的门在我面前关上。这句话是对的，但我用它用得太多了。',-1),l("hr",null,null,-1),l("p",null,'威尼斯。一整夜。全部垮掉。靠金钱和计谋拿下的东西，一验真章就全没了。我那天在信里嘲笑威尼斯人——"一夜之间便失去了一切"。但我在笑谁？我的民兵也是一天之内在普拉托散掉的。我靠笔杆子写的《君主论》也没换来任何东西。我笑威尼斯人的时候，笑的是我自己。',-1),l("hr",null,null,-1),l("p",null,'"欲建新共和国者，务必拿定主意，是打算让它扩张领土和实力，还是局限于狭小的畛域。"我这辈子最大的问题就是这两个都没选。我想让佛罗伦萨伟大，但我不敢让她流血。我想让共和国安宁，但我又写了献给君主的小册子。左右不是人。索代里尼没拿定主意，我也没拿定主意。我们俩的区别只是他比我更有权力搞砸。',-1),l("hr",null,null,-1),l("p",null,'……不对。让我重新想。第六章最后一句——"只能予以忍受，将其视为取得罗马的伟业所必要的弊端"。这不是放弃。这是接受代价。我选了罗马模式——扩张、纷争、护民官的咆哮、平民和贵族的互撕——然后我写出了这些。如果我再选一次，我还是选罗马。斯巴达太安静了，安静得像坟墓。威尼斯太精明了，精明到筋骨都是软的。罗马很吵、很乱、很危险——但那才是活着的政治。',-1)])])}const f=n(a,[["render",s]]);export{m as __pageData,f as default};
